const c = $input.first().json;
const text = (c.userText || '').toLowerCase();
const ids = c.ta_table_ids || {};

// Detect which tables are relevant
const needsPackages   = ids.packages   && !/umrah|hajj/i.test(text);
const needsUmrah      = ids.umrah_groups && /umrah|hajj|makkah|madinah|saudi/i.test(text);
const needsCars       = ids.cars       && /car|vehicle|rent|suv|sedan|bus/i.test(text);
const needsItineraries = ids.itineraries && /itinerar|day|plan|schedule|trip|tour/i.test(text);

// Extract keyword for package name search (first meaningful word)
const stopWords = new Set(['package','rate','price','cost','details','pls','please','tell','me','the','a','an','is','are','what','how','give','want','need','about','any']);
const words = text.split(/\s+/).filter(w => w.length > 2 && !stopWords.has(w));
const keyword = words[0] || '';

return [{ json: { ...c, _filter: { needsPackages, needsUmrah, needsCars, needsItineraries, keyword } } }];

const c = $('Execute Workflow Trigger').first().json;
const f = $('Code · Detect Intent').first().json._filter;
const today = new Date().toISOString().slice(0, 10);

const packages    = f.needsPackages    ? ($('HTTP · Get Packages').first().json.list    || []) : [];
const umrahGroups = f.needsUmrah       ? ($('HTTP · Get Umrah Groups').first().json.list || []).filter(g => g.departure_date >= today) : [];
const cars        = f.needsCars        ? ($('HTTP · Get Cars').first().json.list        || []) : [];
const itineraries = f.needsItineraries ? ($('HTTP · Get Itineraries').first().json.list || []) : [];

let block = '';

if (packages.length) {
  const lines = packages.map(p => {
    let l = `- ${p.name}`;
    if (p.destination) l += ` | Destination: ${p.destination}`;
    if (p.nights)      l += ` | ${p.nights} nights`;
    if (p.type)        l += ` | Type: ${p.type}`;
    if (p.sell_price || p.base_price) l += ` | Price: ${p.currency||'INR'} ${p.sell_price||p.base_price}/person`;
    if (p.pax_min || p.pax_max) l += ` | Pax: ${p.pax_min||1}-${p.pax_max||''}`;
    try { const inc = JSON.parse(p.inclusions||'[]'); if (inc.length) l += ` | Includes: ${inc.join(', ')}`; } catch(e) {}
    return l;
  }).join('\n');
  block += '\n\n## Travel Packages\n' + lines;
}

if (umrahGroups.length) {
  const lines = umrahGroups.map(g => `- ${g.name} | Departs: ${g.departure_date} | Seats: ${g.seats||0} | ${g.currency||'INR'} ${g.price_per_pax||''}/person`).join('\n');
  block += '\n\n## Upcoming Umrah / Hajj Groups\n' + lines;
}

if (itineraries.length) {
  const lines = itineraries.map(it => {
    let days = []; try { days = JSON.parse(it.days||'[]'); } catch(e) {}
    return `- ${it.title}${it.destination?' | '+it.destination:''} | ${days.length} days`;
  }).join('\n');
  block += '\n\n## Itineraries\n' + lines;
}

if (cars.length) {
  const lines = cars.map(car => `- ${car.name}${car.category?' ('+car.category+')':''} | ${car.seats||'?'} seats | ${car.currency||'INR'} ${car.daily_rate||0}/day${car.plate_no?' | Plate: '+car.plate_no:''}`).join('\n');
  block += '\n\n## Available Cars for Rent\n' + lines;
}

return [{ json: { ...c, taContextBlock: block } }];
